/* StaLineMapper.countSubRoutes - 대표 siteCd의 하위 노선 존재 여부 */
SELECT COUNT(*)
FROM site_info s
WHERE s.del_yn = 'N'
  AND s.parent_site_cd = #{parentSiteCd}

SELECT line_json
FROM site_sta_line
WHERE site_cd = #{siteCd}
  AND direction_cd = #{directionCd}
  AND seg_no = #{segNo}
  AND use_yn = 'Y'
    LIMIT 1

mapper.update:
UPDATE site_sta_line
SET line_json = #{lineJson}
, start_lng = #{startLng}
, start_lat = #{startLat}
, updated_at = CURRENT_TIMESTAMP
WHERE site_cd = #{siteCd}
AND direction_cd = #{directionCd}
AND seg_no = #{segNo}
